#include <stdio.h>

static long long cube(long long value);

int main(void) {
    long long value;
    if (scanf("%lld", &value) != 1) return 1;
    printf("%lld\n", cube(value));
    return 0;
}

static long long cube(long long value) { return value * value * value; }
